const b = $json.body ?? $json;
const need = ['session_id', 'patient_id', 'audio_uri'];
for (const k of need) {
  if (!b[k]) throw new Error(`Falta campo obligatorio: ${k}`);
}
return [{
  json: {
    session_id: String(b.session_id),
    patient_id: String(b.patient_id),
    physician_id: b.physician_id ? String(b.physician_id) : null,
    audio_uri: String(b.audio_uri),
    clinical: b.clinical && typeof b.clinical === 'object' ? b.clinical : {},
    meta: { received_at: new Date().toISOString() }
  }
}];

