const root = $('Code — Validar payload').first().json;
const items = $input.all();
let acoustic = {};
let nlp = {};
for (const it of items) {
  const j = it.json;
  if (j.f0_mean != null || j.jitter != null || j.opensmile) acoustic = j;
  if (j.transcript != null || j.ttr != null || j.whisper) nlp = j;
}
if (!acoustic || Object.keys(acoustic).length === 0) acoustic = items[0]?.json ?? {};
if (!nlp || Object.keys(nlp).length === 0) nlp = items[1]?.json ?? {};
return [{
  json: {
    session_id: root.session_id,
    patient_id: root.patient_id,
    clinical: root.clinical,
    acoustic,
    nlp
  }
}];

const p = $json;
const f0 = p.acoustic?.f0_mean ?? p.f0_mean ?? 0;
const jit = (p.acoustic?.jitter ?? p.jitter ?? 0) * 100;
const shim = (p.acoustic?.shimmer ?? p.shimmer ?? 0) * 100;
const ttr = p.nlp?.ttr ?? p.ttr ?? 0;
const wpm = p.nlp?.words_per_min ?? p.words_per_min ?? 0;
const chartAcoustic = {
  type: 'bar',
  data: {
    labels: ['F0 (Hz)', 'Jitter %', 'Shimmer %'],
    datasets: [{
      label: 'Acústico',
      data: [Math.round(f0 * 10) / 10, Math.round(jit * 100) / 100, Math.round(shim * 100) / 100],
      backgroundColor: ['#3b82f6', '#ef4444', '#f59e0b']
    }]
  },
  options: { plugins: { title: { display: true, text: 'Resumen Acústico' } } }
};
const chartLing = {
  type: 'bar',
  data: {
    labels: ['TTR (diversidad)', 'Palabras/min'],
    datasets: [{
      label: 'Lingüístico',
      data: [Math.round(ttr * 1000) / 1000, Math.round(wpm * 10) / 10],
      backgroundColor: ['#8b5cf6', '#10b981']
    }]
  },
  options: { plugins: { title: { display: true, text: 'Métricas NLP' } } }
};
const prob = (p.p_parkinson ?? p.probability ?? 0);
const pct = Math.round(prob * 1000) / 10;
const chartRisk = {
  type: 'doughnut',
  data: {
    labels: ['Riesgo Parkinson', 'Resto'],
    datasets: [{
      data: [pct, Math.max(0, 100 - pct)],
      backgroundColor: [pct >= 70 ? '#ef4444' : pct >= 50 ? '#f59e0b' : '#10b981', '#e5e7eb']
    }]
  },
  options: { plugins: { title: { display: true, text: `Probabilidad estimada: ${pct}%` } } }
};
const enc = (c) => encodeURIComponent(JSON.stringify(c));
return [{
  json: {
    ...p,
    charts: {
      acoustic_png: `https://quickchart.io/chart?c=${enc(chartAcoustic)}&w=500&h=300&format=png`,
      linguistic_png: `https://quickchart.io/chart?c=${enc(chartLing)}&w=500&h=300&format=png`,
      risk_png: `https://quickchart.io/chart?c=${enc(chartRisk)}&w=400&h=400&format=png`
    }
  }
}];
